function tutorialAbstractionCards(items: TutorialAbstractionReport["abstractions"]): string {
  if (items.length === 0) return "<article><h3>кё°лЎқлҗң м¶”мғҒнҷ”к°Җ м—ҶмҠөлӢҲлӢӨ.</h3><p>н•өмӢ¬ нҢҢмқј мҲҳм—…мқ„ лӢӨмӢң мғқм„ұн•ҳл©ҙ мқҙкіім—җ нҠңнҶ лҰ¬м–ј мһҘмқҙ мҢ“мһ…лӢҲлӢӨ.</p></article>";
  return items.map((item) => `<article class="tutorial-abstraction-card" id="${htmlAnchor(item.id)}"><h3>Chapter ${item.chapterNumber}: ${escapeHtml(item.name)}</h3><p>${escapeHtml(item.description)}</p><p class="muted">relationships ${item.relationshipCount}</p><p>${escapeHtml(item.chapterGoal)}</p><h4>Relevant Files</h4>${tutorialFileLinks(item.relevantFiles)}</article>`).join("");
}

function tutorialFileLinks(items: TutorialAbstractionReport["abstractions"][number]["relevantFiles"]): string {
  if (items.length === 0) return "<p class=\"muted\">кё°лЎқлҗң кҙҖл Ё нҢҢмқјмқҙ м—ҶмҠөлӢҲлӢӨ.</p>";
  return `<ul>${items.map((item) => `<li><a href="${escapeHtml(item.lessonHref.replace(/^html\//, ""))}">${escapeHtml(item.filePath)}</a> <a class="source-link" href="../${escapeHtml(item.sourceHref)}">мӣҗліё м—ҙкё°</a></li>`).join("")}</ul>`;
}

function decisionRecordCards(items: DecisionRecordReport["records"]): string {
  if (items.length === 0) return "<article><h3>кё°лЎқлҗң decision recordк°Җ м—ҶмҠөлӢҲлӢӨ.</h3><p>л¶„м„қ лҰ¬нҸ¬нҠёлҘј лӢӨмӢң мғқм„ұн•ҳм„ёмҡ”.</p></article>";
  return items.map((item) => `<article class="decision-record-card" id="${htmlAnchor(item.id)}"><h3>${escapeHtml(item.title)}</h3><p class="muted">${escapeHtml(item.status)} В· ${escapeHtml(item.scope)} В· ${escapeHtml(item.tags.join(", "))}</p><h4>Context</h4><p>${escapeHtml(item.context)}</p><h4>Decision</h4><p>${escapeHtml(item.decision)}</p><h4>Positive Consequences</h4>${list(item.consequences.positive)}<h4>Negative Consequences</h4>${list(item.consequences.negative)}<h4>Related Reports</h4>${list(item.relatedReports.map((report) => `${report.label}: ${report.href}`))}</article>`).join("");
}

